import{_ as e,o as r,c as a,ag as s}from"./chunks/framework.Bb4_ZWqO.js";const m=JSON.parse('{"title":"datasole","titleTemplate":"Realtime TypeScript Framework","description":"","frontmatter":{"layout":"home","title":"datasole","titleTemplate":"Realtime TypeScript Framework","hero":{"name":"datasole","text":"Realtime TypeScript framework","tagline":"Binary WebSocket transport in a Web Worker. JSON Patch state sync. Typed RPC. CRDTs. 35.6 KB gzip on the wire. One npm install.","actions":[{"theme":"brand","text":"Start the tutorial","link":"/tutorials"},{"theme":"alt","text":"See examples","link":"/examples"},{"theme":"alt","text":"GitHub","link":"https://github.com/mayanklahiri/datasole"}]},"features":[{"icon":"⚡","title":"Performance","details":"WebSocket runs in a Web Worker — no UI jank. Binary frames with pako compression (60–80% smaller than JSON). SharedArrayBuffer zero-copy transfer. Four server concurrency models. Client IIFE 20.9 KB gzip."},{"icon":"✓","title":"Correctness","details":"122 unit tests + 38 e2e tests (Playwright, headless Chromium, production bundle — desktop 1280×720 + Pixel 7 mobile). CI matrix on Node 22 LTS and Node 24. Coverage thresholds enforced on every push. Strict TypeScript with .d.ts on every export. Shared types between client and server — no codegen, no drift."},{"icon":"🛠","title":"Developer experience","details":"Single npm package for client, server, shared types, and Web Worker. Works with React, Vue, Svelte, Next.js, Express, NestJS, Fastify. Progressive 10-step tutorial. Copy-paste examples. AGENTS.md for AI coding assistants."},{"icon":"🔄","title":"State synchronization","details":"Server→client sync via RFC 6902 JSON Patch (only diffs over the wire). Bidirectional sync via built-in CRDTs — LWW registers, PN counters, LWW maps. Configurable sync channels with immediate, batched, or debounced flush."},{"icon":"🏗","title":"Server architecture","details":"Four concurrency strategies: async (event loop), thread-per-connection, thread pool, process isolation. Pluggable persistence: memory, Redis, Postgres. Frame-level rate limiting. Session persistence across reconnections."},{"icon":"📊","title":"Observability","details":"Prometheus and OpenTelemetry metric exporters. Connection counts, message rates, latency histograms, error rates. Quality gate with bundle size tracking on every CI push."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),i={name:"index.md"};function n(o,t,d,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[s('<h2 id="data-flow-patterns" tabindex="-1">Data flow patterns <a class="header-anchor" href="#data-flow-patterns" aria-label="Permalink to &quot;Data flow patterns&quot;">​</a></h2><p>datasole supports seven composable patterns — use one, or layer them:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Direction</th><th>Mechanism</th></tr></thead><tbody><tr><td>RPC</td><td>client → server → client</td><td>Typed request/response with correlation IDs</td></tr><tr><td>Server events</td><td>server → clients</td><td>Broadcast (stock ticker, notifications)</td></tr><tr><td>Client events</td><td>client → server</td><td>Fire-and-forget (chat, analytics)</td></tr><tr><td>Live state</td><td>server → clients</td><td>JSON Patch auto-sync (dashboards, leaderboards)</td></tr><tr><td>CRDT sync</td><td>client ↔ server</td><td>Conflict-free merge (collaborative editing)</td></tr><tr><td>Sync channels</td><td>configurable</td><td>Immediate, batched, or debounced flush</td></tr><tr><td>Combinations</td><td>any</td><td>All patterns compose freely</td></tr></tbody></table><h2 id="bundle-sizes" tabindex="-1">Bundle sizes <a class="header-anchor" href="#bundle-sizes" aria-label="Permalink to &quot;Bundle sizes&quot;">​</a></h2><p>All bundles include their runtime dependencies (pako, fast-json-patch). Verified by CI on every push.</p><table tabindex="0"><thead><tr><th>Bundle</th><th>Loaded by</th><th style="text-align:right;">Raw</th><th style="text-align:right;">Gzip</th></tr></thead><tbody><tr><td><strong>Client IIFE</strong> (min)</td><td><code>&lt;script&gt;</code> tag</td><td style="text-align:right;">67.1 KB</td><td style="text-align:right;"><strong>20.9 KB</strong></td></tr><tr><td><strong>Worker IIFE</strong> (min)</td><td>Web Worker</td><td style="text-align:right;">46.5 KB</td><td style="text-align:right;"><strong>14.7 KB</strong></td></tr><tr><td><strong>Shared</strong> (ESM)</td><td>Server or client import</td><td style="text-align:right;">261.0 KB</td><td style="text-align:right;">64.5 KB</td></tr><tr><td><strong>Server</strong> (ESM)</td><td>Node.js <code>import</code></td><td style="text-align:right;">430.8 KB</td><td style="text-align:right;">100.5 KB</td></tr></tbody></table><p>A browser downloads the client IIFE (<strong>20.9 KB</strong> gzip) and the worker (<strong>14.7 KB</strong> gzip) = <strong>35.6 KB</strong> total.</p><h2 id="how-it-compares" tabindex="-1">How it compares <a class="header-anchor" href="#how-it-compares" aria-label="Permalink to &quot;How it compares&quot;">​</a></h2><p>See the full <a href="/datasole/comparison">comparison with Socket.IO, Ably, Pusher, Liveblocks, and PartyKit</a>.</p>',9)])])}const g=e(i,[["render",n]]);export{m as __pageData,g as default};
